const input = $input.first().json;
const a = input.transcricao;
const b = input.texto;

function retornaNaoNulo(a, b) {
    if (a !== null && a !== undefined && a !== '') {
        return String(a).trim();
    }
    if (b !== null && b !== undefined && b !== '') {
        return String(b).trim();
    }
    return '';
}

const resultado = retornaNaoNulo(a, b);

return [{
    json: {
        mensagem: resultado
    }
}];

const dadosNode = $('Dados2').first();
if (!dadosNode || !dadosNode.json || !dadosNode.json.payload) {
  return [{ json: { numero: 'erro_dados_ausentes' } }];
}

const data = dadosNode.json.payload;
if (!data._data || !data._data.Info) {
  return [{ json: { numero: 'erro_estrutura_invalida' } }];
}

const campos = [data._data.Info.SenderAlt, data._data.Info.Chat];
let numero = null;

// Primeiro loop: busca por @s.whatsapp.net
for (let campo of campos) {
  if (campo && typeof campo === 'string' && campo.includes('@s.whatsapp.net')) {
    numero = campo.split('@')[0].split(':')[0];
    break;
  }
}

// Segundo loop: fallback se não encontrou
if (!numero) {
  for (let campo of campos) {
    if (campo && typeof campo === 'string') {
      numero = campo.replace('@lid', '').split('@')[0].split(':')[0];
      break;
    }
  }
}

// Fallback final
if (!numero || numero === '') {
  numero = 'numero_nao_encontrado';
}

return [{ json: { numero: numero } }];

const query = $input.first().json.query || {};
const timeRange = query.timeRange || 'MES_ATUAL';
const startDate = query.startDate;
const endDate = query.endDate;

const dateExpr = "COALESCE(a.data_hora_fim, a.data_hora_inicio)";
let dateFilter = '';

switch(timeRange) {
  case 'HOJE':
    dateFilter = `DATE(${dateExpr}) = CURRENT_DATE`;
    break;
  case 'MES_ATUAL':
    dateFilter = `EXTRACT(MONTH FROM ${dateExpr}) = EXTRACT(MONTH FROM CURRENT_DATE) AND EXTRACT(YEAR FROM ${dateExpr}) = EXTRACT(YEAR FROM CURRENT_DATE)`;
    break;
  case 'ULTIMO_MES':
    dateFilter = `${dateExpr} >= CURRENT_DATE - INTERVAL '30 days'`;
    break;
  case 'ULTIMOS_6_MESES':
    dateFilter = `${dateExpr} >= CURRENT_DATE - INTERVAL '6 months'`;
    break;
  case 'PERSONALIZADO':
    if (startDate && endDate) {
      dateFilter = `${dateExpr} BETWEEN '${startDate}' AND '${endDate}'`;
    } else {
      dateFilter = `EXTRACT(MONTH FROM ${dateExpr}) = EXTRACT(MONTH FROM CURRENT_DATE) AND EXTRACT(YEAR FROM ${dateExpr}) = EXTRACT(YEAR FROM CURRENT_DATE)`;
    }
    break;
  default:
    dateFilter = `EXTRACT(MONTH FROM ${dateExpr}) = EXTRACT(MONTH FROM CURRENT_DATE) AND EXTRACT(YEAR FROM ${dateExpr}) = EXTRACT(YEAR FROM CURRENT_DATE)`;
}

return [{
  json: {
    dateFilter: dateFilter,
    timeRange: timeRange
  }
}];

function num(v) {
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : 0;
}
function int(v) {
  const n = parseInt(v);
  return Number.isFinite(n) ? n : 0;
}

let overall = {};
let top = {};
let service = {};
let typeItems = [];

try { overall = $('Query Overall Metrics1').first().json || {}; } catch (e) { overall = {}; }
try { top = $('Query Top Attendant2').first().json || {}; } catch (e) { top = {}; }
try { service = $('Query Service Metrics2').first().json || {}; } catch (e) { service = {}; }
try { typeItems = $('Query Type Averages2').all() || []; } catch (e) { typeItems = []; }

const typeScoreAverages = {};
for (const item of typeItems) {
  const row = item.json || {};
  if (row.tipo_atendimento) {
    typeScoreAverages[row.tipo_atendimento] = num(row.avg_score).toFixed(1);
  }
}

const result = {
  overallMetrics: {
    total: int(overall.total),
    avgScore: num(overall.avgscore).toFixed(1),
    positivePercent: num(overall.positivepercent).toFixed(1),
    negativePercent: num(overall.negativepercent).toFixed(1),
    topAttendant: top.id_atendente
      ? `${top.id_atendente} ${num(top.avg_score).toFixed(1)}`
      : null
  },
  serviceMetrics: {
    avgHandlingMinutes: num(service.avghandlingminutes).toFixed(1),
    abandonmentPercent: 3.2,
    typeDistribution: {
      'Dúvida': int(service.duvidas),
      'Reclamação': int(service.reclamacoes),
      'Suporte Técnico': int(service.suporte),
      'Vendas': int(service.vendas)
    }
  },
  typeScoreAverages
};

return [{ json: result }];

const query = $input.first().json.query || {};
const timeRange = query.timeRange || 'MES_ATUAL';
const sentiment = query.sentiment || 'Todos';
const startDate = query.startDate;
const endDate = query.endDate;
const idAtendimento = query.idAtendimento; 
const cliente = query.cliente;             

const dateExpr = "COALESCE(a.data_hora_fim, a.data_hora_inicio)";
let dateFilter = '';

switch (timeRange) {
  case 'HOJE':
    dateFilter = `DATE(${dateExpr}) = CURRENT_DATE`;
    break;
  case 'MES_ATUAL':
    dateFilter = `EXTRACT(MONTH FROM ${dateExpr}) = EXTRACT(MONTH FROM CURRENT_DATE) AND EXTRACT(YEAR FROM ${dateExpr}) = EXTRACT(YEAR FROM CURRENT_DATE)`;
    break;
  case 'ULTIMO_MES':
    dateFilter = `${dateExpr} >= CURRENT_DATE - INTERVAL '30 days'`;
    break;
  case 'ULTIMOS_6_MESES':
    dateFilter = `${dateExpr} >= CURRENT_DATE - INTERVAL '6 months'`;
    break;
  case 'PERSONALIZADO':
    dateFilter = (startDate && endDate)
      ? `${dateExpr} BETWEEN '${startDate}' AND '${endDate}'`
      : `EXTRACT(MONTH FROM ${dateExpr}) = EXTRACT(MONTH FROM CURRENT_DATE) AND EXTRACT(YEAR FROM ${dateExpr}) = EXTRACT(YEAR FROM CURRENT_DATE)`;
    break;
  default:
    dateFilter = `EXTRACT(MONTH FROM ${dateExpr}) = EXTRACT(MONTH FROM CURRENT_DATE) AND EXTRACT(YEAR FROM ${dateExpr}) = EXTRACT(YEAR FROM CURRENT_DATE)`;
}

return [{ json: { dateFilter, timeRange, sentiment, idAtendimento, cliente } }];

const rows = $input.all().map(i => i.json);
if (!rows.length) {
  return [{ json: { csv: 'ID,Atendente,Cliente,Data/Hora,Score,Sentimento,Tipo,Mensagem\n' } }];
}

const headers = Object.keys(rows[0]);
const escape = (v) => {
  if (v == null) return '';
  const s = String(v);
  const needsQuotes = /[",\n]/.test(s);
  return needsQuotes ? '"' + s.replace(/"/g, '""') + '"' : s;
};

const csv = [
  headers.join(','),
  ...rows.map(r => headers.map(h => escape(r[h])).join(','))
].join('\n');

return [{ json: { csv } }];

const items = $input.all();
const hasData = items.length > 0 && items[0].json;
const data = hasData ? items[0].json : {};

const getNum = (v, d = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};

const result = {
  overallMetrics: {
    total: getNum(data.total),
    avgHandlingMinutes: Number(getNum(data.avg_handling_minutes).toFixed(1)),
    abandonmentPercent: Number(getNum(data.abandonment_percent).toFixed(1))
  },
  typeDistribution: {
    'Dúvida': getNum(data.duvida_count),
    'Reclamação': getNum(data.reclamacao_count),
    'Suporte Técnico': getNum(data.suporte_count),
    'Vendas': getNum(data.vendas_count)
  },
  typeScoreAverages: {
    'Dúvida': Number(getNum(data.duvida_avg_score).toFixed(1)),
    'Reclamação': Number(getNum(data.reclamacao_avg_score).toFixed(1)),
    'Suporte Técnico': Number(getNum(data.suporte_avg_score).toFixed(1)),
    'Vendas': Number(getNum(data.vendas_avg_score).toFixed(1))
  }
};

return [{ json: result }];

const rows = $input.all().map(i => i.json);
const id = $('Extract ID').first().json.id_atendimento || 'export';

if (!rows.length) {
  return [{ json: { csv: 'Timestamp,Remetente,Tipo,Mensagem,URL_Mídia\n', filename: `conversa_${id}.csv` } }];
}

const escape = (value) => {
  if (value == null) return '';
  const str = String(value);
  const needsQuotes = /[,"\n\r]/.test(str);
  return needsQuotes ? '"' + str.replace(/"/g, '""') + '"' : str;
};

const headers = ['timestamp', 'remetente', 'tipo', 'mensagem', 'url_midia'];
const csvContent = [
  'Timestamp,Remetente,Tipo,Mensagem,URL_Mídia',
  ...rows.map(row => headers.map(h => escape(row[h])).join(','))
].join('\n');

return [{ json: { csv: csvContent, filename: `conversa_${id}.csv` } }];

const req = $input.first().json || {};
const q = req.query || req;

return [{
