    limit: parseInt(q.limit) || 100,
    offset: parseInt(q.offset) || 0
  }
}];

const p = $input.first().json;
const dateExpr = "COALESCE(a.data_hora_fim, a.data_hora_inicio)";
let dateFilter = '1=1';

switch (p.timeRange) {
