  case 'PERSONALIZADO': dateFilter = p.startDate && p.endDate ? `${dateExpr} BETWEEN '${p.startDate}' AND '${p.endDate}'` : dateFilter; break;
}

return [{ json: { ...p, dateFilter } }];

const inputs = $input.all();

// registros da query (Query Audit List1)
const conversations = inputs
  .filter(i => i.json.id_atendimento !== undefined)
  .map(i => i.json);

// total do count
const countItem = inputs.find(i => i.json.total_count !== undefined);
const total = countItem ? Number(countItem.json.total_count) : 0;

return [{
  json: {
    total,
    conversations
  }
